import azure.functions as func
import pickle
import logging
import traceback
from datetime import datetime

app = func.FunctionApp()

@app.service_bus_queue_trigger(
    arg_name="msg",
    queue_name="job-queue",
    connection="ServiceBusConnection"
)
def process_queue_message(msg: func.ServiceBusMessage):
    logging.info('Python ServiceBus queue trigger function processing message')
    
    try:
        message_body = msg.get_body()
        
        deserialized_data = pickle.loads(message_body)
        
        logging.info(f'Message ID: {msg.message_id}')
        logging.info(f'Deserialized data type: {type(deserialized_data).__name__}')
        
        process_job(deserialized_data, msg)
        
        logging.info(f'Successfully processed message {msg.message_id}')
        
    except pickle.UnpicklingError as e:
        logging.error(f'Failed to unpickle message {msg.message_id}: {str(e)}')
        logging.error(traceback.format_exc())
        raise
    except Exception as e:
        logging.error(f'Error processing message {msg.message_id}: {str(e)}')
        logging.error(traceback.format_exc())
        raise


def process_job(data, msg: func.ServiceBusMessage):
    if isinstance(data, dict):
        job_type = data.get('job_type', 'unknown')
        logging.info(f'Processing job type: {job_type}')
        
        if job_type == 'data_processing':
            process_data_job(data)
        elif job_type == 'report_generation':
            process_report_job(data)
        elif job_type == 'batch_operation':
            process_batch_job(data)
        else:
            logging.warning(f'Unknown job type: {job_type}')
            process_generic_job(data)
    
    elif isinstance(data, list):
        logging.info(f'Processing list of {len(data)} items')
        for idx, item in enumerate(data):
            logging.info(f'Processing item {idx + 1}/{len(data)}')
            process_item(item)
    
    elif isinstance(data, object):
        logging.info(f'Processing custom object: {type(data).__name__}')
        process_custom_object(data)
    
    else:
        logging.info(f'Processing data: {data}')


def process_data_job(job_data):
    logging.info('Executing data processing job')
    dataset = job_data.get('dataset', [])
    operation = job_data.get('operation', 'transform')
    parameters = job_data.get('parameters', {})
    
    logging.info(f'Dataset size: {len(dataset)}')
    logging.info(f'Operation: {operation}')
    logging.info(f'Parameters: {parameters}')
    
    results = []
    for record in dataset:
        processed_record = apply_operation(record, operation, parameters)
        results.append(processed_record)
    
    logging.info(f'Processed {len(results)} records')
    return results


def process_report_job(job_data):
    logging.info('Executing report generation job')
    report_type = job_data.get('report_type')
    data_source = job_data.get('data_source')
    filters = job_data.get('filters', {})
    
    logging.info(f'Report type: {report_type}')
    logging.info(f'Data source: {data_source}')
    logging.info(f'Filters: {filters}')
    
    report_data = generate_report(report_type, data_source, filters)
    logging.info('Report generated successfully')
    return report_data


def process_batch_job(job_data):
    logging.info('Executing batch operation job')
    operations = job_data.get('operations', [])
    batch_size = job_data.get('batch_size', 100)
    
    logging.info(f'Number of operations: {len(operations)}')
    logging.info(f'Batch size: {batch_size}')
    
    for i in range(0, len(operations), batch_size):
        batch = operations[i:i + batch_size]
        logging.info(f'Processing batch {i // batch_size + 1}')
        execute_batch(batch)
    
    logging.info('Batch operations completed')


def process_generic_job(data):
    logging.info('Processing generic job')
    for key, value in data.items():
        logging.info(f'{key}: {value}')


def process_item(item):
    logging.info(f'Processing item: {item}')


def process_custom_object(obj):
    logging.info(f'Processing custom object with attributes: {dir(obj)}')
    if hasattr(obj, 'execute'):
        obj.execute()
    elif hasattr(obj, 'process'):
        obj.process()
    elif hasattr(obj, 'run'):
        obj.run()


def apply_operation(record, operation, parameters):
    if operation == 'transform':
        return {k: str(v).upper() if isinstance(v, str) else v for k, v in record.items()}
    elif operation == 'filter':
        return record if all(record.get(k) == v for k, v in parameters.items()) else None
    elif operation == 'aggregate':
        return record
    else:
        return record


def generate_report(report_type, data_source, filters):
    return {
        'report_type': report_type,
        'generated_at': datetime.utcnow().isoformat(),
        'data_source': data_source,
        'filters': filters,
        'status': 'completed'
    }


def execute_batch(batch):
    for operation in batch:
        logging.info(f'Executing operation: {operation}')